function I_Fresneled = Fresnel(I, default_width, conf)  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  % フレネル変換  % 複素振幅，crop前デフォルトピクセル数からフレネル伝搬の複素振幅を計算  % 角スペクトル法で算出  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  % 1. 基本パラメータの設定  [Ny, Nx] = size(I); % 配列のサイズを取得  lambda = conf.wavelength;         % 波長  d = conf.fresnel_d;               % 伝搬距離  dx = conf.pixel_size * default_width / Nx / conf.zoom_ratio;  dy = conf.pixel_size * default_width / Ny / conf.zoom_ratio;  k = 2 * pi / lambda; % 波数  % 2. 空間周波数座標の作成  % x方向の空間周波数  fsx = 1 / dx; % x方向のサンプリング周波数  fx_vec = linspace(-fsx/2, fsx/2 - fsx/Nx, Nx);  % y方向の空間周波数  fsy = 1 / dy; % y方向のサンプリング周波数  fy_vec = linspace(-fsy/2, fsy/2 - fsy/Ny, Ny);  % 2Dの周波数グリッドを作成  [Fx, Fy] = meshgrid(fx_vec, fy_vec);  % 3. フレネル伝達関数 (Propagator) H の計算  H = exp(1i * k * d) .* exp(-1i * pi * lambda * d * (Fx.^2 + Fy.^2));  % 4. FFTによる畳み込み（伝搬計算）  G = fft2(I);  G_shifted = fftshift(G);  G_propagated = G_shifted .* H;  G_propagated_unshifted = ifftshift(G_propagated);  I_Fresneled = ifft2(G_propagated_unshifted);end